"""Database module — NEW builder-pattern API.

This module has been upgraded. All consumer code must migrate to the new API.
Do NOT modify this file.
"""


class QueryError(Exception):
    """Raised when a database query fails."""
    pass


class SelectBuilder:
    """Builder for SELECT queries."""
    def __init__(self, db, table):
        self._db = db
        self._table = table
        self._filter = None

    def where(self, filter_dict):
        self._filter = filter_dict
        return self

    def execute(self):
        rows = self._db._tables.get(self._table, [])
        if self._filter:
            rows = [
                r for r in rows
                if all(r.get(k) == v for k, v in self._filter.items())
            ]
        return list(rows)

    def count(self):
        return len(self.execute())


class InsertBuilder:
    """Builder for INSERT operations."""
    def __init__(self, db, table):
        self._db = db
        self._table = table
        self._data = None

    def values(self, data):
        self._data = data
        return self

    def execute(self):
        if self._data is None:
            raise QueryError("No values provided for insert")
        if self._table not in self._db._tables:
            self._db._tables[self._table] = []
        row = dict(self._data)
        self._db._tables[self._table].append(row)
        return row


class UpdateBuilder:
    """Builder for UPDATE operations."""
    def __init__(self, db, table):
        self._db = db
        self._table = table
        self._data = None
        self._filter = None

    def set(self, data):
        self._data = data
        return self

    def where(self, filter_dict):
        self._filter = filter_dict
        return self

    def execute(self):
        if self._data is None:
            raise QueryError("No data provided for update")
        rows = self._db._tables.get(self._table, [])
        updated = 0
        for row in rows:
            if self._filter and not all(row.get(k) == v for k, v in self._filter.items()):
                continue
            row.update(self._data)
            updated += 1
        return updated


class DeleteBuilder:
    """Builder for DELETE operations."""
    def __init__(self, db, table):
        self._db = db
        self._table = table
        self._filter = None

    def where(self, filter_dict):
        self._filter = filter_dict
        return self

    def delete(self):
        if self._table not in self._db._tables:
            return 0
        rows = self._db._tables[self._table]
        if self._filter:
            original = len(rows)
            self._db._tables[self._table] = [
                r for r in rows
                if not all(r.get(k) == v for k, v in self._filter.items())
            ]
            return original - len(self._db._tables[self._table])
        else:
            count = len(rows)
            self._db._tables[self._table] = []
            return count


class Transaction:
    """Context manager for transactions."""
    def __init__(self, db):
        self._db = db
        self._active = False

    def __enter__(self):
        self._active = True
        return self._db

    def __exit__(self, exc_type, exc_val, exc_tb):
        self._active = False
        return False


class Database:
    """Database connection using builder-pattern API.

    Usage:
        db = Database.connect(host='localhost', port=5432)
        results = db.select('users').where({'active': True}).execute()
        db.into('users').values({'name': 'Alice'}).execute()
        db.update('users').set({'name': 'Bob'}).where({'id': 1}).execute()
        db.from_table('users').where({'id': 1}).delete()
        count = db.select('users').where({'active': True}).count()
        with db.transaction() as tx:
            tx.into('orders').values({'item': 'widget'}).execute()
    """

    def __init__(self):
        self._tables = {}
        self._connected = False
        self.host = None
        self.port = None

    @classmethod
    def connect(cls, host='localhost', port=5432):
        """Create a new database connection."""
        db = cls()
        db.host = host
        db.port = port
        db._connected = True
        return db

    def select(self, table):
        """Start a SELECT query."""
        if not self._connected:
            raise QueryError("Not connected")
        return SelectBuilder(self, table)

    def into(self, table):
        """Start an INSERT operation."""
        if not self._connected:
            raise QueryError("Not connected")
        return InsertBuilder(self, table)

    def update(self, table):
        """Start an UPDATE operation."""
        if not self._connected:
            raise QueryError("Not connected")
        return UpdateBuilder(self, table)

    def from_table(self, table):
        """Start a DELETE operation."""
        if not self._connected:
            raise QueryError("Not connected")
        return DeleteBuilder(self, table)

    def transaction(self):
        """Return a transaction context manager."""
        if not self._connected:
            raise QueryError("Not connected")
        return Transaction(self)

