"""User management module."""
from database import Database, DatabaseError


def get_user_store():
    """Create a database connection for the user store."""
    db = Database('localhost', 5432)
    return db


def find_user(db, username):
    """Find a user by username."""
    results = db.query('users', {'username': username})
    if results:
        return results[0]
    return None


def create_user(db, username, email, role='member'):
    """Create a new user."""
    existing = db.query('users', {'username': username})
    if existing:
        raise DatabaseError(f"User {username} already exists")
    user_data = {'username': username, 'email': email, 'role': role, 'active': True}
    return db.insert('users', user_data)


def update_user_email(db, username, new_email):
    """Update a user's email address."""
    count = db.update('users', {'username': username}, {'email': new_email})
    if count == 0:
        raise DatabaseError(f"User {username} not found")
    return count


def deactivate_user(db, username):
    """Deactivate a user account."""
    count = db.update('users', {'username': username}, {'active': False})
    return count


def list_active_users(db):
    """List all active users."""
    return db.query('users', {'active': True})

