    """Remove a product from the catalog."""
    count = db.delete('products', {'id': product_id})
    if count == 0:
        raise DatabaseError(f"Product {product_id} not found")
    return count


def count_products_in_category(db, category):
    """Count products in a given category."""
    return db.count('products', {'category': category})


def get_product(db, product_id):
    """Get a single product by ID."""
    results = db.query('products', {'id': product_id})
    if results:
        return results[0]
    return None

