"""Order processing module."""
from database import Database, DatabaseError


def get_order_db():
    """Create a database connection for orders."""
    db = Database('localhost', 5432)
    return db


def find_orders(db, customer_id):
    """Find all orders for a customer."""
    return db.query('orders', {'customer_id': customer_id})


def place_order(db, customer_id, items, total):
    """Place a new order with transaction support."""
    order_data = {'customer_id': customer_id, 'items': items, 'total': total, 'status': 'pending'}
    db.begin()
    try:
        result = db.insert('orders', order_data)
        for item in items:
            db.update('products', {'id': item['product_id']}, {'stock': item['new_stock']})
        db.commit()
        return result
    except DatabaseError:
        raise


def update_order_status(db, order_id, status):
    """Update the status of an order."""
    count = db.update('orders', {'id': order_id}, {'status': status})
    if count == 0:
        raise DatabaseError(f"Order {order_id} not found")
    return count


def get_order(db, order_id):
    """Get a single order by ID."""
    results = db.query('orders', {'id': order_id})
    if results:
        return results[0]
    return None

