"""Admin operations module."""
from database import Database, DatabaseError


def bulk_update_prices(db, category, multiplier):
    """Update all product prices in a category by a multiplier."""
    products = db.query('products', {'category': category})
    db.begin()
    try:
        for product in products:
            new_price = product['price'] * multiplier
            db.update('products', {'id': product['id']}, {'price': new_price})
        db.commit()
        return len(products)
    except DatabaseError:
        raise


def purge_inactive_users(db):
    """Delete all inactive users."""
    count = db.delete('users', {'active': False})
    return count


def reset_order_status(db, old_status, new_status):
    """Bulk update order statuses."""
    count = db.update('orders', {'status': old_status}, {'status': new_status})
    return count


def archive_old_orders(db, status):
    """Archive orders with a given status by deleting them."""
    try:
        count = db.delete('orders', {'status': status})
        return count
    except DatabaseError:
        return 0


def promote_user(db, username, new_role):
    """Promote a user to a new role within a transaction."""
    db.begin()
    try:
        db.update('users', {'username': username}, {'role': new_role})
        db.insert('audit_log', {'action': 'promote', 'username': username, 'role': new_role})
        db.commit()
    except DatabaseError:
        raise
